import{_ as d,C as o,o as a,c as i,a3 as e,b as n,w as r,a as s,E as p,a4 as h}from"./chunks/framework.C49Ar5GK.js";const f=JSON.parse('{"title":"从这里开始：先找到你真正缺的那一块","description":"用八分钟诊断自己的强化学习、LLM 和工程基础，再选择适合的 veRL 学习入口","frontmatter":{"title":"从这里开始：先找到你真正缺的那一块","description":"用八分钟诊断自己的强化学习、LLM 和工程基础，再选择适合的 veRL 学习入口","lesson":{"stage":"00 · 定位","order":0,"time":"8–15 分钟","level":"零基础可读","question":"我应该从哪里开始，怎样才算真的学会了 veRL？"}},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":null}'),c={name:"guide/index.md"};function u(g,t,E,_,b,A){const l=o("Mermaid");return a(),i("div",null,[t[1]||(t[1]=e('<h1 id="从这里开始-先找到你真正缺的那一块" tabindex="-1">从这里开始：先找到你真正缺的那一块 <a class="header-anchor" href="#从这里开始-先找到你真正缺的那一块" aria-label="Permalink to &quot;从这里开始：先找到你真正缺的那一块&quot;">​</a></h1><p>如果你打开 veRL 后看到 Ray、rollout、actor、advantage、TransferQueue 一起出现，觉得每个词都认识、连起来却不知道系统在做什么，这是正常的。你缺的通常不是更多术语，而是一条能反复验证的主线。</p><p>本站只围绕一条主线展开：</p><blockquote><p><strong>一个问题怎样变成回答，回答怎样得到评价，评价怎样变成梯度，新参数又怎样回到下一轮生成？</strong></p></blockquote><p>先用下面的诊断找到起点。不要因为某项不会就先去补一整本教材；只补足当前阶段需要的最小知识。</p><h2 id="八分钟入场诊断" tabindex="-1">八分钟入场诊断 <a class="header-anchor" href="#八分钟入场诊断" aria-label="Permalink to &quot;八分钟入场诊断&quot;">​</a></h2><p>不查资料，试着口头回答。答案模糊也没关系，记录你在哪一列最常停顿。</p><table tabindex="0"><thead><tr><th>你能解释的问题</th><th>如果答不上，真正缺的是什么</th><th>建议入口</th></tr></thead><tbody><tr><td>模型生成下一个 token 时，实际输出的是什么？</td><td>概率分布、采样与 log-prob</td><td><a href="/losh_has_blog/verl-learning/fundamentals/llm">LLM 如何成为策略</a></td></tr><tr><td>reward=1 为什么不能直接当作 loss 反向传播？</td><td>随机策略与策略梯度</td><td><a href="/losh_has_blog/verl-learning/algorithms/policy-gradient">策略梯度这座桥</a></td></tr><tr><td>advantage 为正，究竟希望哪个概率变大？</td><td>credit assignment 与目标函数</td><td><a href="/losh_has_blog/verl-learning/fundamentals/rl">强化学习的完整闭环</a></td></tr><tr><td>old policy、current policy、rollout policy 有何区别？</td><td>PPO 的数据时序</td><td><a href="/losh_has_blog/verl-learning/algorithms/ppo">PPO 与 GAE</a></td></tr><tr><td>GRPO 为什么同一问题要生成多个回答？</td><td>组内相对基线</td><td><a href="/losh_has_blog/verl-learning/algorithms/grpo-family">GRPO、Dr.GRPO 与 DAPO</a></td></tr><tr><td>一次 rollout 与普通聊天推理有何异同？</td><td>训练所需的轨迹字段</td><td><a href="/losh_has_blog/verl-learning/practice/first-run">第一次可验证实验</a></td></tr><tr><td>Ray actor、veRL Worker、GPU 进程是不是同一个概念？</td><td>控制面和计算面的边界</td><td><a href="/losh_has_blog/verl-learning/internals/architecture">整体架构</a></td></tr><tr><td>想换奖励或优势估计器时，应该改哪一层？</td><td>扩展边界</td><td><a href="/losh_has_blog/verl-learning/customization/extension-map">扩展点地图</a></td></tr></tbody></table><p>判断方法：</p><ul><li>前三题不稳，从第 01 站开始；这不是“基础差”，而是在避免后面只会抄配置。</li><li>前五题能答、但没跑过 veRL，直接去第 03 站完成 smoke run。</li><li>已经能训练，但看不懂数据在哪里，去第 04 站沿一个 <code>uid</code> 追踪。</li><li>已经改过奖励，准备改算法或吞吐，去第 05 站，同时回查你用到的算法章节。</li></ul><h2 id="先把全局闭环装进脑中" tabindex="-1">先把全局闭环装进脑中 <a class="header-anchor" href="#先把全局闭环装进脑中" aria-label="Permalink to &quot;先把全局闭环装进脑中&quot;">​</a></h2><p>下面这张图现在只需看懂箭头，不必理解每个公式。</p>',12)),(a(),n(h,null,{default:r(()=>[p(l,{id:"mermaid-159",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20P%5B%E9%97%AE%E9%A2%98%20prompt%5D%20--%3E%20R%5B%E7%AD%96%E7%95%A5%20rollout%3Cbr%2F%3E%E9%80%90%20token%20%E7%94%9F%E6%88%90%5D%0A%20%20%20%20R%20--%3E%20S%5B%E5%AE%8C%E6%95%B4%E5%9B%9E%E7%AD%94%20response%5D%0A%20%20%20%20S%20--%3E%20W%5B%E5%A5%96%E5%8A%B1%20reward%3Cbr%2F%3E%E5%9B%9E%E7%AD%94%E6%9C%89%E5%A4%9A%E5%A5%BD%5D%0A%20%20%20%20W%20--%3E%20A%5B%E4%BC%98%E5%8A%BF%20advantage%3Cbr%2F%3E%E6%AF%94%E5%9F%BA%E7%BA%BF%E5%A5%BD%E5%A4%9A%E5%B0%91%5D%0A%20%20%20%20A%20--%3E%20U%5B%E7%AD%96%E7%95%A5%E6%9B%B4%E6%96%B0%20update%3Cbr%2F%3E%E6%94%B9%E5%8F%98%20token%20%E6%A6%82%E7%8E%87%5D%0A%20%20%20%20U%20--%3E%7C%E5%90%8C%E6%AD%A5%E6%96%B0%E6%9D%83%E9%87%8D%7C%20R%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e(`<p>用人话说：模型先按当前习惯写几份答案；评分规则告诉它哪些更好；算法把“好多少”变成每个 token 的训练信号；优化器只做一小步，避免新习惯突然偏离太远；新权重再交给生成引擎继续收集经验。</p><p>专业地说：LLM 是参数化策略 (\\pi_\\theta)，rollout 产生由 token 动作组成的轨迹，奖励经过基线或价值函数构造优势估计 (\\hat A_t)，策略梯度目标用 (\\log \\pi_\\theta(a_t\\mid s_t)\\hat A_t) 调整参数，PPO/GRPO 等方法再处理更新幅度、基线和样本组织问题。</p><p>这两段说的是同一件事。课程中每个概念都会先给直觉，再给严格表达，最后落到源码字段。</p><h2 id="这不是目录-而是六个通关站点" tabindex="-1">这不是目录，而是六个通关站点 <a class="header-anchor" href="#这不是目录-而是六个通关站点" aria-label="Permalink to &quot;这不是目录，而是六个通关站点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>站点</th><th>核心任务</th><th>你要留下的证据</th></tr></thead><tbody><tr><td>00 定位</td><td>找到知识缺口，固定源码版本</td><td>一份自测结果和学习计划</td></tr><tr><td>01 地基</td><td>把语言生成映射成 RL</td><td>手画状态、动作、奖励、策略关系图</td></tr><tr><td>02 算法</td><td>看懂 PPO/GRPO 输入与输出</td><td>从公式标出每个张量的 shape 和来源</td></tr><tr><td>03 实验</td><td>跑完首个训练 step</td><td>命令、解析配置、日志、样本和指标</td></tr><tr><td>04 源码</td><td>沿一个 <code>uid</code> 跟完闭环</td><td>一张带函数名与字段名的时序图</td></tr><tr><td>05 改造</td><td>做一次可测的自定义改动</td><td>单元测试、A/B 基线与失败回退方案</td></tr></tbody></table><p>完整的每日安排在<a href="./learning-plan">六周学习计划</a>。如果你只想解决眼前问题，可以按上表跳转；但自定义算法前至少应通过 01、02、04 三站。</p><h2 id="每一课应该怎样读" tabindex="-1">每一课应该怎样读 <a class="header-anchor" href="#每一课应该怎样读" aria-label="Permalink to &quot;每一课应该怎样读&quot;">​</a></h2><p>页面会反复使用同一种节奏：</p><ol><li><strong>问题</strong>：先知道这一节在解决什么，不从名词定义开始。</li><li><strong>人话模型</strong>：允许不精确，但必须能形成可操作直觉。</li><li><strong>专业模型</strong>：用公式、shape、边界条件把直觉校准。</li><li><strong>源码落点</strong>：找到文件、函数和真实字段，不停在架构图。</li><li><strong>误区与实验</strong>：主动触发一次错误或反例。</li><li><strong>通关检查</strong>：能解释、能定位、能留下可复现证据。</li></ol><div class="tip custom-block"><p class="custom-block-title">学习时同时打开三个窗口</p><p>左边放课程，中间放固定提交的源码，右边放你自己的 <code>learning-log.md</code>。每遇到一个新字段，记录“谁写入、谁读取、shape、何时失效”，比抄类名有效得多。</p></div><h2 id="怎样判断自己不是-看懂了而已" tabindex="-1">怎样判断自己不是“看懂了而已” <a class="header-anchor" href="#怎样判断自己不是-看懂了而已" aria-label="Permalink to &quot;怎样判断自己不是“看懂了而已”&quot;">​</a></h2><p>完成课程后，你应能在不看网页的情况下回答：</p><ul><li>rollout 为什么既是推理，又不是普通的线上推理；</li><li>reward、token-level reward、advantage、return、loss 分别由谁产生；</li><li>V1 训练器中一批数据什么时候只传 <code>KVBatchMeta</code>，什么时候真正读取 TensorDict；</li><li>actor、reference、critic、reward、rollout 角色哪些必需、哪些取决于算法；</li><li>新 actor 权重何时进入推理引擎，过旧样本会造成什么问题；</li><li>换奖励、换组内基线、换 replay 采样和换推理后端，各自最小改动面在哪里；</li><li>优化吞吐前应采集什么证据，怎样避免“速度快了但算法语义变了”。</li></ul><p>如果只能背调用链，却不能预测删掉一个字段后哪里先报错，还没真正掌握。反过来，如果你能先画出数据契约，再去源码确认细节，就已经具备改框架的能力。</p><h2 id="现在做第一件事" tabindex="-1">现在做第一件事 <a class="header-anchor" href="#现在做第一件事" aria-label="Permalink to &quot;现在做第一件事&quot;">​</a></h2><p>在笔记里写下三行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我的目标：例如“给代码生成任务接入沙箱奖励”</span></span>
<span class="line"><span>我的当前证据：例如“跑过 GRPO，但解释不了 old_log_probs”</span></span>
<span class="line"><span>我的第一个里程碑：例如“本周追完一个 uid 的 rollout → update”</span></span></code></pre></div><p>然后打开<a href="./learning-plan">六周学习计划</a>，把与你目标无关的选修项划掉。学习框架的目的不是遍历所有文件，而是建立足够准确的模型，支持下一次判断。</p>`,18))])}const v=d(c,[["render",u]]);export{f as __pageData,v as default};
